+
+      results.push({
+        scenario,
+        adaptationTime: adaptationTimeMs,
+        target: 0.05, // ms
+        achieved: adaptationTimeMs <= 0.05
+      });
+    }
+
+    return {
+      scenarios: results,
+      averageAdaptation: results.reduce((sum, r) => sum + r.adaptationTime, 0) / results.length,
+      successRate: results.filter(r => r.achieved).length / results.length
+    };
+  }
